// server/src/sockets/chatSocket.ts import { Server, Socket } from 'socket.io';

interface UserSocket extends Socket { userId?: number; userRole?: string; }

export const initializeChatSocket = (io: Server) => { io.on('connection', (socket: UserSocket) => { console.log('Usuario conectado:', socket.id);

// Autenticar y unir a room
socket.on('authenticate', async ({ userId, token }) => {
  // Verificar JWT
  const user = await verifyToken(token);
  socket.userId = user.id;
  socket.userRole = user.role;
  socket.join(`user_${userId}`);

  // Marcar como online
  await updateUserStatus(userId, 'online');

  // Notificar a otros
  io.emit('user:online', { userId });
});

// Enviar mensaje
socket.on('message:send', async (data) => {
  const { conversationId, message, recipientId } = data;

  // Guardar en BD
  const savedMessage = await saveMessage({
    conversationId,
    senderId: socket.userId,
    message,
    timestamp: new Date()
  });

  // Enviar al destinatario
  io.to(`user_${recipientId}`).emit('message:receive', savedMessage);

  // Confirmar al emisor
  socket.emit('message:sent', savedMessage);

  // Crear notificación
  await createNotification(recipientId, 'new_message', savedMessage);
});

// Typing indicator
socket.on('typing:start', ({ conversationId, recipientId }) => {
  io.to(`user_${recipientId}`).emit('typing:start', {
    conversationId,
    userId: socket.userId
  });
});

socket.on('typing:stop', ({ conversationId, recipientId }) => {
  io.to(`user_${recipientId}`).emit('typing:stop', {
    conversationId,
    userId: socket.userId
  });
});

// Marcar como leído
socket.on('message:read', async ({ messageId, conversationId }) => {
  await markAsRead(messageId, socket.userId);
  // Notificar al emisor
  const message = await getMessage(messageId);
  io.to(`user_${message.senderId}`).emit('message:read', {
    messageId,
    readBy: socket.userId,
    readAt: new Date()
  });
});

// Desconexión
socket.on('disconnect', async () => {
  if (socket.userId) {
    await updateUserStatus(socket.userId, 'offline');
    io.emit('user:offline', { userId: socket.userId });
  }
});
}); };

Front end (react hook)

// client/src/hooks/useChat.ts import { useEffect, useState, useCallback } from 'react'; import io, { Socket } from 'socket.io-client';

interface Message { id: number; conversationId: number; senderId: number; message: string; timestamp: Date; isRead: boolean; }

export const useChat = (userId: number, token: string) => { const [socket, setSocket] = useState<Socket | null>(null); const [messages, setMessages] = useState<Message[]>([]); const [isConnected, setIsConnected] = useState(false); const [typingUsers, setTypingUsers] = useState<Set<number>>(new Set());

useEffect(() => { const newSocket = io(process.env.REACT_APP_SOCKET_URL, { auth: { token } });

newSocket.on('connect', () => {
  setIsConnected(true);
  newSocket.emit('authenticate', { userId, token });
});

newSocket.on('disconnect', () => {
  setIsConnected(false);
});

newSocket.on('message:receive', (message: Message) => {
  setMessages(prev => [...prev, message]);
  // Reproducir sonido de notificación
  playNotificationSound();
});

newSocket.on('typing:start', ({ userId }) => {
  setTypingUsers(prev => new Set(prev).add(userId));
});

newSocket.on('typing:stop', ({ userId }) => {
  setTypingUsers(prev => {
    const newSet = new Set(prev);
    newSet.delete(userId);
    return newSet;
  });
});

setSocket(newSocket);

return () => {
  newSocket.close();
};
}, [userId, token]);

const sendMessage = useCallback((conversationId: number, message: string, recipientId: number) => { if (socket) { socket.emit('message:send', { conversationId, message, recipientId }); } }, [socket]);

const startTyping = useCallback((conversationId: number, recipientId: number) => { if (socket) { socket.emit('typing:start', { conversationId, recipientId }); } }, [socket]);

const stopTyping = useCallback((conversationId: number, recipientId: number) => { if (socket) { socket.emit('typing:stop', { conversationId, recipientId }); } }, [socket]);

return { socket, messages, isConnected, typingUsers, sendMessage, startTyping, stopTyping }; };

