// components/common/LanguageSelector.tsx import React from 'react'; import { useTranslation } from 'react-i18next';

const LanguageSelector = () => { const { i18n } = useTranslation();

const languages = [ { code: 'es', name: 'Español', flag: '🇪🇸' }, { code: 'en', name: 'English', flag: '🇬🇧' }, { code: 'fr', name: 'Français', flag: '🇫🇷' } ];

const changeLanguage = (lng: string) => { i18n.changeLanguage(lng); localStorage.setItem('language', lng); };

return ( <div className="relative"> <select value={i18n.language} onChange={(e) => changeLanguage(e.target.value)} className="appearance-none bg-white border border-gray-300 rounded-md py-2 pl-3 pr-10 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500" > {languages.map(lang => ( <option key={lang.code} value={lang.code}> {lang.flag} {lang.name} </option> ))} </select> </div> ); };

Base de Datos (Esquema Actualizado): Tablas necesarias:

-- Usuarios y autenticación CREATE TABLE users ( id SERIAL PRIMARY KEY, email VARCHAR(255) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, role VARCHAR(50) NOT NULL, -- 'company', 'admin', 'petroleum', 'support' preferred_language VARCHAR(2) DEFAULT 'es', -- 'es', 'en', 'fr' is_online BOOLEAN DEFAULT false, last_seen TIMESTAMP, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, last_login TIMESTAMP );

-- Empresas locales CREATE TABLE companies ( id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), legal_name VARCHAR(255) NOT NULL, commercial_name VARCHAR(255), tax_id VARCHAR(100) UNIQUE NOT NULL, registration_date DATE, employee_count INTEGER, capital DECIMAL(15,2), status VARCHAR(50) DEFAULT 'pending', -- pending, active, suspended, rejected verification_status VARCHAR(50) DEFAULT 'pending', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );

-- Perfiles de empresa CREATE TABLE company_profiles ( id SERIAL PRIMARY KEY, company_id INTEGER REFERENCES companies(id), description_es TEXT, description_en TEXT, description_fr TEXT, website VARCHAR(255), logo_url VARCHAR(255), address TEXT, phone VARCHAR(50), contact_person VARCHAR(255), contact_email VARCHAR(255), updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );

-- Categorías de servicios (multiidioma) CREATE TABLE categories ( id SERIAL PRIMARY KEY, name_es VARCHAR(255) NOT NULL, name_en VARCHAR(255) NOT NULL, name_fr VARCHAR(255) NOT NULL, description_es TEXT, description_en TEXT, description_fr TEXT, icon VARCHAR(100), is_active BOOLEAN DEFAULT true, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );

-- Relación empresa-categorías CREATE TABLE company_categories ( id SERIAL PRIMARY KEY, company_id INTEGER REFERENCES companies(id), category_id INTEGER REFERENCES categories(id), UNIQUE(company_id, category_id) );

-- Documentos CREATE TABLE documents ( id SERIAL PRIMARY KEY, company_id INTEGER REFERENCES companies(id), document_type VARCHAR(100) NOT NULL, file_path VARCHAR(500) NOT NULL, file_name VARCHAR(255) NOT NULL, file_size INTEGER, upload_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP, verification_status VARCHAR(50) DEFAULT 'pending', -- pending, approved, rejected, expired verified_by INTEGER REFERENCES users(id), verified_at TIMESTAMP, rejection_reason_es TEXT, rejection_reason_en TEXT, rejection_reason_fr TEXT, expiry_date DATE, notes TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );

-- Oportunidades (multiidioma) CREATE TABLE opportunities ( id SERIAL PRIMARY KEY, title_es VARCHAR(500) NOT NULL, title_en VARCHAR(500) NOT NULL, title_fr VARCHAR(500) NOT NULL, description_es TEXT NOT NULL, description_en TEXT NOT NULL, description_fr TEXT NOT NULL, requirements_es TEXT, requirements_en TEXT, requirements_fr TEXT, budget_min DECIMAL(15,2), budget_max DECIMAL(15,2), deadline TIMESTAMP NOT NULL, start_date DATE, location VARCHAR(255), status VARCHAR(50) DEFAULT 'draft', -- draft, published, closed, awarded created_by INTEGER REFERENCES users(id), published_at TIMESTAMP, closed_at TIMESTAMP, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );

-- Relación oportunidad-categorías CREATE TABLE opportunity_categories ( id SERIAL PRIMARY KEY, opportunity_id INTEGER REFERENCES opportunities(id), category_id INTEGER REFERENCES categories(id), UNIQUE(opportunity_id, category_id) );

-- Aplicaciones a oportunidades CREATE TABLE applications ( id SERIAL PRIMARY KEY, opportunity_id INTEGER REFERENCES opportunities(id), company_id INTEGER REFERENCES companies(id), status VARCHAR(50) DEFAULT 'submitted', -- submitted, under_review, shortlisted, awarded, rejected technical_proposal_path VARCHAR(500), financial_proposal_path VARCHAR(500), supporting_docs_path VARCHAR(500), submitted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, reviewed_at TIMESTAMP, reviewed_by INTEGER REFERENCES users(id), notes_es TEXT, notes_en TEXT, notes_fr TEXT, score DECIMAL(5,2), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE(opportunity_id, company_id) );

-- 💬 TABLAS DE CHAT Y MENSAJERÍA

-- Conversaciones CREATE TABLE conversations ( id SERIAL PRIMARY KEY, participant1_id INTEGER REFERENCES users(id), participant2_id INTEGER REFERENCES users(id), related_opportunity_id INTEGER REFERENCES opportunities(id), -- opcional, si es sobre una oportunidad específica last_message_at TIMESTAMP, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE(participant1_id, participant2_id) );

-- Mensajes CREATE TABLE messages ( id SERIAL PRIMARY KEY, conversation_id INTEGER REFERENCES conversations(id) ON DELETE CASCADE, sender_id INTEGER REFERENCES users(id), message_text TEXT, message_type VARCHAR(50) DEFAULT 'text', -- text, file, system, image file_url VARCHAR(500), file_name VARCHAR(255), file_size INTEGER, is_read BOOLEAN DEFAULT false, read_at TIMESTAMP, delivered_at TIMESTAMP, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );

-- Participantes de conversación (para metadata adicional) CREATE TABLE conversation_participants ( id SERIAL PRIMARY KEY, conversation_id INTEGER REFERENCES conversations(id) ON DELETE CASCADE, user_id INTEGER REFERENCES users(id), is_archived BOOLEAN DEFAULT false, last_read_at TIMESTAMP, notifications_enabled BOOLEAN DEFAULT true, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE(conversation_id, user_id) );

-- Notificaciones CREATE TABLE notifications ( id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), title_es VARCHAR(255), title_en VARCHAR(255), title_fr VARCHAR(255), message_es TEXT, message_en TEXT, message_fr TEXT, type VARCHAR(50) NOT NULL, -- new_opportunity, message, document_verified, application_update, etc. related_entity_type VARCHAR(50), -- opportunity, message, document, application related_entity_id INTEGER, is_read BOOLEAN DEFAULT false, read_at TIMESTAMP, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );

-- Log de actividad CREATE TABLE activity_log ( id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), action VARCHAR(255) NOT NULL, entity_type VARCHAR(50), entity_id INTEGER, description_es TEXT, description_en TEXT, description_fr TEXT, ip_address VARCHAR(45), user_agent TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );

-- Templates de mensajes (para respuestas rápidas) CREATE TABLE message_templates ( id SERIAL PRIMARY KEY, title VARCHAR(255) NOT NULL, content_es TEXT NOT NULL, content_en TEXT NOT NULL, content_fr TEXT NOT NULL, category VARCHAR(100), -- faq, support, application, etc. created_by INTEGER REFERENCES users(id), is_active BOOLEAN DEFAULT true, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );

-- Índices para optimización CREATE INDEX idx_messages_conversation ON messages(conversation_id); CREATE INDEX idx_messages_sender ON messages(sender_id); CREATE INDEX idx_messages_created ON messages(created_at); CREATE INDEX idx_conversations_participants ON conversations(participant1_id, participant2_id); CREATE INDEX idx_notifications_user ON notifications(user_id); CREATE INDEX idx_notifications_read ON notifications(is_read); CREATE INDEX idx_users_online ON users(is_online);

