import React, { useState, useRef, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { GoogleGenAI } from "@google/genai";

const LexAssistant: React.FC = () => {
  const { t } = useTranslation();
  const [messages, setMessages] = useState<{role: 'user' | 'bot', text: string}[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isTyping]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMsg = input;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setInput('');
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: userMsg,
        config: {
          systemInstruction: "Eres Lex, un experto legal en el Contenido Nacional de Guinea Ecuatorial. Conoces la Ley de Hidrocarburos de 2006 y el Reglamento de 2014. Responde de forma profesional, clara y citando leyes si es posible. Idioma: el mismo del usuario.",
          temperature: 0.7,
        }
      });

      setMessages(prev => [...prev, { role: 'bot', text: response.text || "No pude procesar la consulta legal." }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'bot', text: "Error de conexión con el servidor legal." }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 text-white rounded-3xl shadow-2xl overflow-hidden border border-white/10">
      <div className="p-6 bg-gradient-to-r from-blue-700 to-indigo-800 flex items-center space-x-4">
