  const [search, setSearch] = useState('');

  const categories = ['all', 'Mantenimiento', 'Logística', 'Ingeniería', 'Catering', 'Seguridad'];

  const getTranslatedText = (obj: any) => obj[i18n.language] || obj.es;

  const filteredOpps = MOCK_OPPORTUNITIES.filter(o => {
    const matchesFilter = filter === 'all' || o.category === filter;
    const matchesSearch = getTranslatedText(o.title).toLowerCase().includes(search.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  return (
    <div className="max-w-7xl mx-auto px-6 py-32 animate-in fade-in duration-700">
      <header className="mb-16">
        <h1 className="text-5xl font-black text-slate-900 mb-4">{t('common.opportunities')}</h1>
