      </header>

      <div className="flex flex-col lg:flex-row gap-12">
        <aside className="w-full lg:w-72 space-y-6">
          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
             <h3 className="text-xs font-black uppercase tracking-widest text-slate-400 mb-6">Categorías</h3>
             <div className="space-y-2">
                {categories.map(c => (
                  <button key={c} onClick={() => setFilter(c)} className={`w-full text-left px-4 py-2 rounded-xl text-sm font-bold transition-all ${filter === c ? 'bg-blue-600 text-white' : 'text-slate-500 hover:bg-slate-50'}`}>
                    {c === 'all' ? 'Todas' : c}
                  </button>
                ))}
             </div>
          </div>
        </aside>

        <div className="flex-1 space-y-8">
          {filteredOpps.map(opp => (
            <div key={opp.id} className="bg-white p-10 rounded-[3rem] border border-slate-100 hover:shadow-2xl transition-all group">
              <div className="flex justify-between items-start mb-6">
                 <div>
                    <span className="text-[10px] font-black uppercase text-blue-600 mb-2 block tracking-widest">{opp.category}</span>
                    <h3 className="text-3xl font-black text-slate-900 group-hover:text-blue-600 transition-colors">{getTranslatedText(opp.title)}</h3>
                 </div>
                 <div className="text-right">
                    <p className="text-2xl font-black text-slate-900">${opp.budget.toLocaleString()}</p>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Presupuesto USD</p>
                 </div>
              </div>
              <p className="text-slate-500 mb-10 text-lg leading-relaxed line-clamp-2">{getTranslatedText(opp.description)}</p>
              <div className="flex justify-between items-center border-t border-slate-50 pt-8">
                 <div className="flex items-center text-orange-600 font-bold text-sm">
                    <span className="mr-2">⏳</span> Cierra: {opp.deadline}
                 </div>
                 <div className="flex space-x-4">
                    <Link to={`/opportunity/${opp.id}`} className="px-8 py-3 rounded-2xl border-2 border-slate-100 font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-all">
                       {t('common.details')}
